package ui.admin;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import model.*;import util.*;import ui.common.TableStyle;
public class InternshipApprovalPanel extends JPanel{ JTable table=new JTable(); public InternshipApprovalPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Approve / Reject Internship Posts"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);JPanel p=UITheme.panel();JButton ap=UITheme.button("Approve");JButton rj=UITheme.button("Reject");p.add(ap);p.add(rj);add(p,BorderLayout.SOUTH);ap.addActionListener(e->status(Constants.JOB_APPROVED));rj.addActionListener(e->status(Constants.JOB_REJECTED));load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Title","Field","City","Status"},0);for(Internship j:new InternshipController().pending())m.addRow(new Object[]{j.getId(),j.getTitle(),j.getField(),j.getCity(),j.getStatus()});table.setModel(m);TableStyle.apply(table);} void status(String s){int r=table.getSelectedRow();if(r<0)return;new InternshipController().status(Integer.parseInt(table.getValueAt(r,0).toString()),s);load();}}
